def validate(args, output):
    arr = list(args[0]) if args[0] else []
    out = list(output) if output else []
    n = len(arr)
    pre = [0] * (n + 1)
    for i in range(n):
        pre[i + 1] = pre[i] + arr[i]
    # can we walk prefix indices 0..n, at each step either KEEP node i
    # (emit arr[i], advance by 1) or REMOVE a zero-sum block [i, j)
    # (pre[j]==pre[i], emit nothing), so that emitted values == out?
    m = len(out)
    from functools import lru_cache
    import sys
    sys.setrecursionlimit(100000)
    @lru_cache(maxsize=None)
    def reach(i, k):
        # at prefix index i, having matched k output values
        if i == n:
            return k == m
        # keep node i
        if k < m and arr[i] == out[k] and reach(i + 1, k + 1):
            return True
        # remove a zero-sum block starting at i
        for j in range(i + 1, n + 1):
            if pre[j] == pre[i] and reach(j, k):
                return True
        return False
    if not reach(0, 0):
        return False
    # completeness: no nonempty consecutive sublist of the OUTPUT sums to zero
    opre = [0] * (m + 1)
    for i in range(m):
        opre[i + 1] = opre[i] + out[i]
    seen = set()
    for v in opre:
        if v in seen:
            return False
        seen.add(v)
    return True

