function validate(args, output) {
    const arr = args[0] ? Array.from(args[0]) : [];
    const out = output ? Array.from(output) : [];
    const n = arr.length;
    const pre = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] + arr[i];
    const m = out.length;
    const memo = new Map();
    function reach(i, k) {
        if (i === n) return k === m;
        const key = i * (m + 1) + k;
        if (memo.has(key)) return memo.get(key);
        let res = false;
        if (k < m && arr[i] === out[k] && reach(i + 1, k + 1)) res = true;
        if (!res) {
            for (let j = i + 1; j <= n; j++) {
                if (pre[j] === pre[i] && reach(j, k)) { res = true; break; }
            }
        }
        memo.set(key, res);
        return res;
    }
    if (!reach(0, 0)) return false;
    const opre = new Array(m + 1).fill(0);
    for (let i = 0; i < m; i++) opre[i + 1] = opre[i] + out[i];
    const seen = new Set();
    for (const v of opre) {
        if (seen.has(v)) return false;
        seen.add(v);
    }
    return true;
}

