class Solution:
    def removeZeroSumSublists(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        changed = True
        while changed:
            changed = False
            n = len(vals)
            for i in range(n):
                s = 0
                for j in range(i, n):
                    s += vals[j]
                    if s == 0:
                        vals = vals[:i] + vals[j + 1:]
                        changed = True
                        break
                if changed:
                    break
        dummy = ListNode(0)
        tail = dummy
        for v in vals:
            tail.next = ListNode(v)
            tail = tail.next
        return dummy.next

