var removeZeroSumSublists = function(head) {
    const dummy = new ListNode(0);
    dummy.next = head;
    const last = new Map();
    let s = 0;
    let node = dummy;
    while (node) {
        s += node.val;
        last.set(s, node);
        node = node.next;
    }
    s = 0;
    node = dummy;
    while (node) {
        s += node.val;
        node.next = last.get(s).next;
        node = node.next;
    }
    return dummy.next;
};
